from llama_index.core import StorageContext, load_index_from_storage
from vex import verify
import datetime

# Load potentially stale index
storage_context = StorageContext.from_defaults(persist_dir='./storage')
index = load_index_from_storage(storage_context)
query_engine = index.as_query_engine()

@verify(
    rules=[
        'index data fresher than 30 days',
        'complete context across chunk boundaries',
        'FERPA-compliant: no student data exposure',
        'bias-free educational content'
    ],
    metadata={'last_updated': index.storage_context.persist_dir}
)
def compliant_query(question: str):
    return query_engine.query(question)

result = compliant_query('Current 8th grade reading standards?')
